import{_ as e,o as a,c as i,a2 as t}from"./chunks/framework.D5wUhsuj.js";const n="/docs/assets/user-dropdown.BJ6jnyWS.png",r="/docs/assets/kubeconfig-downloader-ui.CYYe6V-X.png",l="/docs/assets/100-pods-warning.D3Cp-O1y.png",o="/docs/assets/delete-completed-pods-ui.Ddumw9nX.png",p="/docs/assets/k8s-secrets-ui.CsN0uyJh.png",h="/docs/assets/registry-creds-ui.DQR0mrO0.png",m=JSON.parse('{"title":"Kubernetes Resources","description":"","frontmatter":{},"headers":[],"relativePath":"platform/kubernetes.md","filePath":"platform/kubernetes.md","lastUpdated":1783546178000}'),k={name:"platform/kubernetes.md"};function d(c,s,g,u,F,b){return a(),i("div",null,[...s[0]||(s[0]=[t('<h1 id="kubernetes-resources" tabindex="-1">Kubernetes Resources <a class="header-anchor" href="#kubernetes-resources" aria-label="Permalink to &quot;Kubernetes Resources&quot;">​</a></h1><p>prokube runs on Kubernetes. Most users do not need to manage raw Kubernetes objects directly, but Kubernetes concepts still show up when you debug workloads, use <code>kubectl</code>, configure secrets, or hit workspace pod limits.</p><div class="info custom-block"><p class="custom-block-title">Kubernetes documentation</p><p>For Kubernetes features that are not specific to prokube, use the upstream documentation:</p><ul><li><a href="https://kubernetes.io/docs/home/" target="_blank" rel="noreferrer">Kubernetes documentation</a></li><li><a href="https://kubernetes.io/docs/reference/kubectl/" target="_blank" rel="noreferrer"><code>kubectl</code> reference</a></li><li><a href="https://kubernetes.io/docs/tasks/debug/debug-application/debug-running-pod/" target="_blank" rel="noreferrer">Debug running pods</a></li></ul></div><p>This page focuses on prokube-specific behavior.</p><h2 id="workspace-namespaces" tabindex="-1">Workspace Namespaces <a class="header-anchor" href="#workspace-namespaces" aria-label="Permalink to &quot;Workspace Namespaces&quot;">​</a></h2><p>Each <a href="./workspaces.html">workspace</a> has its own Kubernetes namespace. Labs, pipeline steps, model-serving workloads, serverless services, agents, MCP servers, secrets, and related Kubernetes resources run inside that namespace.</p><p>The selected workspace determines which namespace is used by workspace-scoped UI pages and platform tools.</p><h2 id="user-menu-actions" tabindex="-1">User Menu Actions <a class="header-anchor" href="#user-menu-actions" aria-label="Permalink to &quot;User Menu Actions&quot;">​</a></h2><p>Several Kubernetes-related actions are available from the prokube user menu: <strong>Download Kubeconfig</strong>, <strong>Registry Credentials</strong>, and <strong>K8s Secrets</strong>.</p><img class="pk-docs-small-screenshot" src="'+n+'" alt="Kubernetes actions in the prokube user menu"><h2 id="download-kubeconfig" tabindex="-1">Download Kubeconfig <a class="header-anchor" href="#download-kubeconfig" aria-label="Permalink to &quot;Download Kubeconfig&quot;">​</a></h2><p>Use <strong>Download Kubeconfig</strong> from the prokube user menu to download a kubeconfig file for command-line access.</p><p>After the file has been created, the UI shows the download result and basic usage instructions.</p><p><img src="'+r+`" alt="Kubeconfig download dialog" loading="lazy"></p><p>The kubeconfig can be used with tools such as <code>kubectl</code>, <a href="https://k9scli.io/" target="_blank" rel="noreferrer">k9s</a>, and <a href="https://github.com/MuhammedKalkan/OpenLens" target="_blank" rel="noreferrer">OpenLens</a>. Keep the file private. It authenticates as your user and is subject to your workspace permissions.</p><p>Example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KUBECONFIG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/Downloads/kubeconfig.yaml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>If you have access to multiple workspaces, use the namespace that matches the workspace you want to inspect.</p><p>By default, <code>kubectl</code> inside a <a href="./../labs/">Lab</a> uses the in-cluster configuration and the Lab pod&#39;s service account instead of your downloaded kubeconfig. In that case, access is scoped to the namespace of the Lab&#39;s workspace. This only changes if you explicitly configure a different kubeconfig inside the Lab.</p><h2 id="pod-quota-and-cleanup" tabindex="-1">Pod Quota and Cleanup <a class="header-anchor" href="#pod-quota-and-cleanup" aria-label="Permalink to &quot;Pod Quota and Cleanup&quot;">​</a></h2><p>prokube protects clusters with workspace pod quotas. The default limit is 100 pods per workspace. This prevents one workspace from creating enough pods to affect cluster stability.</p><p>Large pipelines can approach this limit quickly because completed pipeline step pods remain in the workspace namespace for a while after the run finishes.</p><p>The prokube UI surfaces pod-quota pressure for the selected workspace next to the workspace selector. The System Status page shows detailed quota usage, including running pods, pending pods, and completed pipeline pods.</p><img class="pk-docs-small-screenshot" src="`+l+'" alt="Pod quota warning next to the workspace selector"><p>When completed pipeline pods are present, the UI offers a cleanup action for them.</p><img class="pk-docs-small-screenshot" src="'+o+'" alt="Delete completed pipeline pods action"><p>Cleanup deletes only completed Argo Workflows / Kubeflow Pipelines pods in <code>Succeeded</code> or <code>Failed</code> state. Running, pending, and unrelated pods are not affected. Pipeline metadata, artifacts, and logs remain available through the usual pipeline and logging views.</p><p>If a workspace repeatedly reaches the pod quota, check for large fan-out pipelines, long-running components, stuck pending pods, and completed pipeline pods that can be cleaned up.</p><h2 id="kubernetes-secrets" tabindex="-1">Kubernetes Secrets <a class="header-anchor" href="#kubernetes-secrets" aria-label="Permalink to &quot;Kubernetes Secrets&quot;">​</a></h2><p>Use <strong>K8s Secrets</strong> from the prokube user menu to create workspace-scoped <a href="https://kubernetes.io/docs/concepts/configuration/secret/" target="_blank" rel="noreferrer">Kubernetes Secrets</a>.</p><p><img src="'+p+'" alt="K8s Secrets dialog" loading="lazy"></p><p>Secrets can be referenced by workloads without putting secret values into notebooks, pipeline code, component YAML, or container images.</p><p>Treat Kubernetes Secrets as workspace-scoped credentials. Users with sufficient workspace access may be able to read secrets in the workspace namespace. Do not store personal credentials or administrator credentials in shared workspaces.</p><h2 id="registry-credentials" tabindex="-1">Registry Credentials <a class="header-anchor" href="#registry-credentials" aria-label="Permalink to &quot;Registry Credentials&quot;">​</a></h2><p>Use <strong>Registry Credentials</strong> from the prokube user menu when workloads in a workspace need to pull images from a private container registry.</p><p><img src="'+h+`" alt="Registry Credentials dialog" loading="lazy"></p><p>Registry credentials are stored as Kubernetes Secrets in the workspace namespace and used as image pull credentials by workloads such as Labs, pipelines, model-serving endpoints, MCP servers, or agents.</p><p>Use credentials intended for the workspace and workload. Do not use broad personal or administrator registry tokens in shared workspaces.</p><h2 id="debug-workloads" tabindex="-1">Debug Workloads <a class="header-anchor" href="#debug-workloads" aria-label="Permalink to &quot;Debug Workloads&quot;">​</a></h2><p>For pod-level debugging, start with the UI pages for the workload. They often surface status, events, warnings, and common configuration problems directly.</p><p>For command-line debugging, use <code>kubectl</code> with the workspace namespace:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all-containers</span></span></code></pre></div><p>Common pod states:</p><ul><li><code>ImagePullBackOff</code>: Kubernetes cannot pull the container image. Check the image name and registry credentials.</li><li><code>CreateContainerConfigError</code>: a referenced secret, config, or key is missing.</li><li><code>CrashLoopBackOff</code>: the container starts and exits repeatedly. Check container logs.</li><li><code>Init:Error</code>: an init container failed. Check the init-container logs with <code>kubectl logs &lt;pod-name&gt; -n &lt;workspace&gt; -c &lt;init-container-name&gt;</code>.</li><li><code>Pending</code>: Kubernetes cannot schedule the pod. Check resource requests, quotas, GPUs, and workspace pod limits.</li></ul><p>If a container fails with <code>exec format error</code>, the image or binary is likely built for the wrong CPU architecture. This commonly happens when an image built on an ARM laptop is used on <code>amd64</code> cluster nodes. Rebuild the image for the target platform, for example with <code>docker buildx build --platform linux/amd64 --push ...</code>.</p><p>For platform log views and retained workload logs, see <a href="./observability.html">Observability</a>. For workspace bucket access and S3-compatible storage, see <a href="./object_storage.html">Object Storage</a>.</p><h2 id="port-forward-services" tabindex="-1">Port Forward Services <a class="header-anchor" href="#port-forward-services" aria-label="Permalink to &quot;Port Forward Services&quot;">​</a></h2><p>For short-lived local debugging, forward a workspace service to your machine:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port-forward</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">service-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">local-por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">service-por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>The service is then available at <code>localhost:&lt;local-port&gt;</code> while the command is running.</p><p>Port forwards are a debugging tool, not production access. If a port forward exits repeatedly, restart it only while you are actively debugging:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">while</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port-forward</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">service-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">local-por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">service-por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">done</span></span></code></pre></div><p>For stable external access, use the platform feature designed for that workload, such as model-serving endpoints, API gateway routes, Knative services, or agent/sandbox ingress.</p><h2 id="check-your-permissions" tabindex="-1">Check Your Permissions <a class="header-anchor" href="#check-your-permissions" aria-label="Permalink to &quot;Check Your Permissions&quot;">​</a></h2><p>Use <code>kubectl auth can-i</code> to check whether your current identity can perform an action in a workspace namespace:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> can-i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> can-i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secrets</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> can-i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>If you use tools such as OpenLens and cannot list cluster namespaces, add the namespaces you can access manually in the tool&#39;s cluster settings. Non-admin users often cannot list every namespace in the cluster.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./workspaces.html">Workspaces</a></li><li><a href="./object_storage.html">Object Storage</a></li><li><a href="./observability.html">Observability</a></li><li><a href="./system_status.html">System Status</a></li><li><a href="./../labs/">Using Labs</a></li><li><a href="./../mlops/pipelines.html">Pipelines</a></li><li><a href="./api_keys.html">API Keys</a></li></ul>`,59)])])}const f=e(k,[["render",d]]);export{m as __pageData,f as default};
